$ErrorActionPreference="Stop"; $LabSubnet="10.0.0.0/24"; $DCAddress="10.0.0.1"; $FileServerName="SRV-FS-001"; $AdminRemoteAddresses=@("10.0.0.100")
function Rule($n,$dir,$act,$proto,$port,$remote){$e=Get-NetFirewallRule -DisplayName $n -ErrorAction SilentlyContinue; if($e){$e|Remove-NetFirewallRule}; $p=@{DisplayName=$n;Direction=$dir;Action=$act;Protocol=$proto;RemoteAddress=$remote;Profile='Any'}; if($port){$p.LocalPort=$port}; New-NetFirewallRule @p|Out-Null; Write-Host "[OK] $n" -ForegroundColor Green}
Set-NetFirewallProfile -Profile Domain,Private,Public -Enabled True -DefaultInboundAction Block -DefaultOutboundAction Allow
Rule "LAB-DC-Allow-DNS-UDP-53-From-Lab" Inbound Allow UDP 53 @($LabSubnet); Rule "LAB-DC-Allow-DNS-TCP-53-From-Lab" Inbound Allow TCP 53 @($LabSubnet)
Rule "LAB-DC-Allow-Kerberos-TCP-88-From-Lab" Inbound Allow TCP 88 @($LabSubnet); Rule "LAB-DC-Allow-Kerberos-UDP-88-From-Lab" Inbound Allow UDP 88 @($LabSubnet); Rule "LAB-DC-Allow-LDAP-TCP-389-From-Lab" Inbound Allow TCP 389 @($LabSubnet); Rule "LAB-DC-Allow-LDAP-UDP-389-From-Lab" Inbound Allow UDP 389 @($LabSubnet); Rule "LAB-DC-Allow-SMB-TCP-445-From-Lab" Inbound Allow TCP 445 @($LabSubnet); Rule "LAB-DC-Allow-RPC-TCP-135-From-Lab" Inbound Allow TCP 135 @($LabSubnet); Rule "LAB-DC-Allow-NTP-UDP-123-From-Lab" Inbound Allow UDP 123 @($LabSubnet); Rule "LAB-DC-Allow-GC-TCP-3268-From-Lab" Inbound Allow TCP 3268 @($LabSubnet); Rule "LAB-DC-Allow-RDP-3389-From-AdminSources" Inbound Allow TCP 3389 $AdminRemoteAddresses
if(Get-NetFirewallRule -DisplayName "LAB-DC-Allow-ICMPv4-From-Lab" -ErrorAction SilentlyContinue){Remove-NetFirewallRule -DisplayName "LAB-DC-Allow-ICMPv4-From-Lab"}; New-NetFirewallRule -DisplayName "LAB-DC-Allow-ICMPv4-From-Lab" -Protocol ICMPv4 -IcmpType 8 -Direction Inbound -Action Allow -RemoteAddress $LabSubnet -Profile Any|Out-Null
if(Test-WSMan $FileServerName -ErrorAction SilentlyContinue){Invoke-Command -ComputerName $FileServerName -ArgumentList $LabSubnet,$DCAddress,$AdminRemoteAddresses -ScriptBlock {param($LabSubnet,$DCAddress,$AdminRemoteAddresses); function R($n,$proto,$port,$remote){$e=Get-NetFirewallRule -DisplayName $n -ErrorAction SilentlyContinue; if($e){$e|Remove-NetFirewallRule}; New-NetFirewallRule -DisplayName $n -Direction Inbound -Action Allow -Protocol $proto -LocalPort $port -RemoteAddress $remote -Profile Any|Out-Null}; Set-NetFirewallProfile -Profile Domain,Private,Public -Enabled True -DefaultInboundAction Block -DefaultOutboundAction Allow; Enable-PSRemoting -Force; R "LAB-FS-Allow-SMB-445-From-Lab" TCP 445 @($LabSubnet); R "LAB-FS-Allow-WinRM-5985-From-DC01" TCP 5985 @($DCAddress); R "LAB-FS-Allow-RDP-3389-From-AdminSources" TCP 3389 $AdminRemoteAddresses; if(Get-NetFirewallRule -DisplayName "LAB-FS-Allow-ICMPv4-From-Lab" -ErrorAction SilentlyContinue){Remove-NetFirewallRule -DisplayName "LAB-FS-Allow-ICMPv4-From-Lab"}; New-NetFirewallRule -DisplayName "LAB-FS-Allow-ICMPv4-From-Lab" -Protocol ICMPv4 -IcmpType 8 -Direction Inbound -Action Allow -RemoteAddress $LabSubnet -Profile Any|Out-Null}}else{Write-Warning "$FileServerName not reachable via WinRM; FS firewall skipped"}
